#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,a[200]={0};
    cin>>n;
    string s;
    cin>>s;
    for(int i=0;i<s.size();i++){
        a[s[i]]++;
    }
    int i=0,j=s.size()-1;
    for(;i<=j;i++){
        if(a[s[i]]==1){
            break;
        }else{
            a[s[i]]--;
        }
    }
    for(;j>=0;j--){
        if(a[s[j]]==1){
            break;
        }else{
            a[s[j]]--;
        }
    }
    cout<<j-i+1;
    return 0;
}
